#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool solve(vector<vector<int>>& matrix, int target) {
        if (matrix.empty() || matrix[0].empty()) return false;
        int rows = matrix.size();
        int cols = matrix[0].size();
        int r = 0, c = cols - 1;
        while (r < rows && c >= 0) {
            int val = matrix[r][c];
            if (val == target) return true;
            else if (val > target) --c;
            else ++r;
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n, m;
    if (!(cin >> n >> m)) return 0;
    vector<vector<int>> matrix(n, vector<int>(m));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            cin >> matrix[i][j];
        }
    }
    int target;
    cin >> target;
    Solution sol;
    bool res = sol.solve(matrix, target);
    cout << (res ? 1 : 0) << "\n";
    return 0;
}
